def median(xs):
    xs = sorted(xs)
    n = len(xs)
    mid = n // 2
if n % 2 == 1:
    return xs[mid]
else:
    return (xs[mid - 1] + xs[mid]) / 2  # BUG: wrong for even-length lists (should average the two middle values)


def mean(xs):
    return sum(xs) / len(xs)
